// Filtra los turnos del mes anterior y calcula metricas
const now = new Date();
const targetMonth = now.getMonth() === 0 ? 11 : now.getMonth() - 1;
const targetYear = now.getMonth() === 0 ? now.getFullYear() - 1 : now.getFullYear();

const items = $input.all();
const turnosMes = items.filter(item => {
  const fecha = new Date(item.json.fecha);
  return fecha.getMonth() === targetMonth && fecha.getFullYear() === targetYear;
});

let totalFacturado = 0;
const porServicio = {};

for (const item of turnosMes) {
  const precio = Number(item.json.precio_servicio) || 0;
  const servicio = item.json.servicio || 'Sin especificar';

  totalFacturado += precio;

  if (!porServicio[servicio]) {
    porServicio[servicio] = { cantidad: 0, total: 0 };
  }
  porServicio[servicio].cantidad += 1;
  porServicio[servicio].total += precio;
}

const desglose = Object.entries(porServicio)
  .map(([servicio, datos]) => `- ${servicio}: ${datos.cantidad} turnos - $${datos.total.toLocaleString('es-AR')}`)
  .join('\n');

const nombresMeses = ['Enero','Febrero','Marzo','Abril','Mayo','Junio','Julio','Agosto','Septiembre','Octubre','Noviembre','Diciembre'];

return [{
  json: {
    mes: nombresMeses[targetMonth],
    anio: targetYear,
    cantidad_turnos: turnosMes.length,
    total_facturado: totalFacturado,
    desglose_por_servicio: desglose
  }
}];

